    16→object PdfDownloader {
    17→    private const val TAG = "CourtAssistant"
    18→    private val client = OkHttpClient.Builder()
    19→        .followRedirects(true)
    20→        .connectTimeout(30, TimeUnit.SECONDS)
    21→        .readTimeout(60, TimeUnit.SECONDS)
