    24→    /**
    25→     * Download PDFs from URLs. For SPA pages (hash routes), we can't use Jsoup.
    26→     * Instead we try direct download first, then queue for WebView if needed.
    27→     */
    28→    suspend fun downloadFromUrls(context: Context, db: AppDatabase, smsId: Long, urls: List<String>) {
    29→        withContext(Dispatchers.IO) {
    30→            for (url in urls) {
    31→                try {
    32→                    Log.d(TAG, "PdfDownloader: processing url=$url")
    33→                    if (url.lowercase().endsWith(".pdf")) {
    34→                        downloadPdf(context, db, smsId, url, "")
    35→                    } else {
    36→                        val pdfLinks = discoverPdfLinks(url)
    37→                        Log.d(TAG, "PdfDownloader: discovered ${pdfLinks.size} pdf links from page")
    38→                        if (pdfLinks.isNotEmpty()) {
    39→                            var downloaded = 0
    40→                            for ((pdfUrl, displayName) in pdfLinks) {
    41→                                if (db.documentDao().findDownloadedByUrlAndSms(pdfUrl, smsId) != null) { downloaded++; continue }
    42→                                val docId = tryDownloadPdf(context, db, smsId, pdfUrl, displayName)
    43→                                if (docId) downloaded++
    44→                            }
    45→                            // 监督：如果未全部下载，保留待下载记录供用户重试
    46→                            if (downloaded < pdfLinks.size) {
    47→                                val pending = db.documentDao().findByUrlAndSms(url, smsId)
    48→                                if (pending == null) {
    49→                                    savePendingUrl(db, smsId, url, "未下载完全($downloaded/${pdfLinks.size}) 点击重试")
    50→                                }
    51→                            } else {
    52→                                // 全部成功，删除该页面的待下载记录
    53→                                val pending = db.documentDao().findByUrlAndSms(url, smsId)
    54→                                if (pending != null && pending.parseStatus == 4) {
    55→                                    db.documentDao().delete(pending)
    56→                                }
    57→                            }
    58→                        } else {
    59→                            Log.d(TAG, "PdfDownloader: no PDFs found via Jsoup, queuing for WebView: $url")
    60→                            savePendingUrl(db, smsId, url)
    61→                        }
    62→                    }
    63→                } catch (e: Exception) {
    64→                    Log.e(TAG, "PdfDownloader: error processing url=$url", e)
    65→                    savePendingUrl(db, smsId, url)
    66→                }
    67→            }
    68→        }
    69→    }
    70→
    71→    private val DOC_KEYWORDS = listOf("传票", "判决", "裁定", "通知", "文书", "送达", "起诉", "应诉", "调解", "下载")
    72→
    73→    private fun discoverPdfLinks(pageUrl: String): List<Pair<String, String>> {
    74→        val result = mutableListOf<Pair<String, String>>() // url to displayName
    75→        try {
    76→            val doc = org.jsoup.Jsoup.connect(pageUrl)
    77→                .userAgent("Mozilla/5.0")
    78→                .timeout(15000)
    79→                .get()
    80→            val baseUri = URI(pageUrl)
    81→
    82→            // 匹配 <a> 链接：URL含.pdf 或 文字含法律文书关键词
    83→            for (link in doc.select("a[href], a[onclick]")) {
    84→                val href = link.attr("abs:href").ifEmpty { link.attr("href") }
    85→                if (href.isBlank()) continue
    86→                val resolved = try { baseUri.resolve(href).toString() } catch (_: Exception) { href }
    87→                val text = link.text().trim()
    88→                val title = link.attr("title").trim()
    89→                val dataName = link.attr("data-name").trim()
    90→                val isPdfUrl = resolved.lowercase().let { it.endsWith(".pdf") || it.contains(".pdf?") }
    91→                val hasKeyword = DOC_KEYWORDS.any { text.contains(it) }
    92→
    93→                if (isPdfUrl || hasKeyword) {
    94→                    // 优先级：dataName > title > text > URL提取的文件名
    95→                    var displayName = dataName.ifEmpty { title }
    96→                    if (displayName.isEmpty()) displayName = text
    97→                    if (displayName.isEmpty()) {
    98→                        displayName = extractNameFromUrl(resolved)
    99→                    }
   100→                    result.add(resolved to displayName)
   101→                }
   102→            }
   103→
   104→            // 匹配 <iframe>/<embed> 嵌入的 PDF
   105→            for (el in doc.select("iframe[src], embed[src], object[data]")) {
   106→                val src = el.attr("abs:src").ifEmpty { el.attr("src").ifEmpty { el.attr("data") } }
   107→                if (src.isBlank()) continue
   108→                val resolved = try { baseUri.resolve(src).toString() } catch (_: Exception) { src }
   109→                if (resolved.lowercase().let { it.contains(".pdf") || it.contains("pdf") }) {
   110→                    val name = el.attr("title").ifEmpty { "嵌入文档" }
   111→                    result.add(resolved to name)
   112→                }
   113→            }
   114→
   115→            // 扫描script标签中的PDF URL
   116→            for (script in doc.select("script")) {
   117→                val scriptText = script.html()
   118→                if (scriptText.contains(".pdf", ignoreCase = true)) {
   119→                    val pattern = Regex("""['"]([^'"]*\.pdf[^'"]*)['"]""", RegexOption.IGNORE_CASE)
   120→                    pattern.findAll(scriptText).forEach { match ->
   121→                        val pdfUrl = match.groupValues[1]
   122→                        val resolved = try {
   123→                            if (pdfUrl.startsWith("http")) pdfUrl
   124→                            else baseUri.resolve(pdfUrl).toString()
   125→                        } catch (_: Exception) { pdfUrl }
   126→                        if (resolved.lowercase().contains(".pdf")) {
   127→                            val name = extractNameFromUrl(resolved)
   128→                            result.add(resolved to name)
   129→                        }
   130→                    }
   131→                }
   132→            }
   133→        } catch (e: Exception) {
   134→            Log.d(TAG, "PdfDownloader: Jsoup failed for $pageUrl: ${e.message}")
   135→        }
   136→        return result.distinctBy { it.first }
   137→    }
   138→
   139→    /** 从URL提取文件名 */
   140→    private fun extractNameFromUrl(url: String): String {
   141→        return try {
   142→            val path = url.substringBefore("?").substringAfterLast("/")
   143→            if (path.isNotBlank() && path.length < 100) {
   144→                path.removeSuffix(".pdf").removeSuffix(".PDF")
   145→            } else {
   146→                "文档"
   147→            }
   148→        } catch (e: Exception) {
   149→            "文档"
   150→        }
   151→    }
