   153→    /** Save a pending URL as a document record so WebView activity can pick it up */
   154→    private suspend fun savePendingUrl(db: AppDatabase, smsId: Long, url: String, label: String = "待下载文书") {
   155→        if (db.documentDao().findByUrlAndSms(url, smsId) != null) return
   156→        db.documentDao().insert(
   157→            DocumentRecord(
   158→                smsId = smsId, fileName = label, filePath = "",
   159→                fileSize = 0, sourceUrl = url, downloadTime = System.currentTimeMillis(),
   160→                parseStatus = 4, displayName = label
   161→            )
   162→        )
   163→    }
   164→
   165→    /** Synchronous version for use in non-suspend context */
   166→    fun savePendingUrlSync(db: AppDatabase, smsId: Long, url: String, label: String = "待下载文书") {
   167→        // 使用Thread在后台执行数据库操作
   168→        Thread {
   169→            try {
   170→                // 先查询是否已存在
   171→                val existing = runBlocking {
   172→                    db.documentDao().findByUrlAndSms(url, smsId)
   173→                }
   174→                if (existing != null) return@Thread
   175→
   176→                // 插入新记录
   177→                runBlocking {
   178→                    db.documentDao().insert(
   179→                        DocumentRecord(
   180→                            smsId = smsId, fileName = label, filePath = "",
   181→                            fileSize = 0, sourceUrl = url, downloadTime = System.currentTimeMillis(),
   182→                            parseStatus = 4, displayName = label
   183→                        )
   184→                    )
   185→                }
   186→            } catch (e: Exception) {
   187→                Log.e(TAG, "Error saving pending URL", e)
   188→            }
   189→        }.start()
   190→    }
   191→
   192→    /** Called from WebViewActivity when a PDF is actually downloaded */
   193→    suspend fun onPdfDownloaded(context: Context, db: AppDatabase, docId: Long, file: File) {
   194→        val doc = db.documentDao().getById(docId) ?: return
   195→        db.documentDao().update(doc.copy(
   196→            fileName = file.name, filePath = file.absolutePath,
   197→            fileSize = file.length(), parseStatus = 0
   198→        ))
   199→        PdfParser.parseAndSync(context, db, docId)
   200→    }
   201→
   202→    /** Try download — check content-type for keyword-matched links that may not be PDF */
   203→    private suspend fun tryDownloadPdf(context: Context, db: AppDatabase, smsId: Long, url: String, displayName: String): Boolean {
   204→        if (url.lowercase().let { it.endsWith(".pdf") || it.contains(".pdf?") }) {
   205→            return downloadPdf(context, db, smsId, url, displayName) > 0
   206→        }
   207→        try {
   208→            val request = Request.Builder().url(url).head().build()
   209→            val response = client.newCall(request).execute()
   210→            val contentType = response.header("Content-Type", "") ?: ""
   211→            if (contentType.contains("pdf", ignoreCase = true)) {
   212→                return downloadPdf(context, db, smsId, url, displayName) > 0
   213→            } else {
   214→                Log.d(TAG, "PdfDownloader: skipping non-PDF url=$url contentType=$contentType")
   215→                return false
   216→            }
   217→        } catch (e: Exception) {
   218→            // HEAD failed, try download anyway
   219→            return downloadPdf(context, db, smsId, url, displayName) > 0
   220→        }
   221→    }
   222→
   223→    suspend fun downloadPdf(context: Context, db: AppDatabase, smsId: Long, url: String, displayName: String = ""): Long {
   224→        val dir = File(context.filesDir, "pdfs").also { it.mkdirs() }
   225→        val fileName = extractFileName(url)
   226→        val file = File(dir, "${System.currentTimeMillis()}_$fileName")
   227→
   228→        Log.d(TAG, "PdfDownloader: downloading $url -> ${file.name}")
   229→        val request = Request.Builder().url(url).build()
   230→        val response = client.newCall(request).execute()
   231→        if (!response.isSuccessful) { Log.e(TAG, "PdfDownloader: HTTP ${response.code}"); return -1 }
   232→        response.body?.byteStream()?.use { input ->
   233→            file.outputStream().use { output -> input.copyTo(output) }
   234→        }
   235→        if (file.length() == 0L) { file.delete(); return -1 }
   236→        Log.d(TAG, "PdfDownloader: downloaded ${file.length()} bytes")
   237→
   238→        val docId = db.documentDao().insert(
   239→            DocumentRecord(
   240→                smsId = smsId, fileName = fileName, filePath = file.absolutePath,
   241→                fileSize = file.length(), sourceUrl = url, downloadTime = System.currentTimeMillis(),
   242→                displayName = displayName.ifEmpty { fileName }
   243→            )
   244→        )
   245→        PdfParser.parseAndSync(context, db, docId)
   246→        return docId
   247→    }
   248→
   249→    private fun extractFileName(url: String): String {
   250→        val path = try { URI(url).path } catch (_: Exception) { null } ?: return "document.pdf"
   251→        val name = path.substringAfterLast("/")
   252→        return if (name.isNotBlank() && name.length < 100) name else "document.pdf"
   253→    }
   254→}
