   106→    /**
   107→     * 自动处理待下载的文档（parseStatus=4）
   108→     * 对于需要WebView手动交互的PDF链接，自动触发下载
   109→     */
   110→    fun autoProcessPendingDocs() {
   111→        viewModelScope.launch(Dispatchers.IO) {
   112→            // 首先清理卡在"处理中"状态的文档（超过5分钟未更新的）
   113→            val stuckDocs = db.documentDao().getStuckProcessingDocs()
   114→            for (stuck in stuckDocs) {
   115→                db.documentDao().update(stuck.copy(parseStatus = 4))
   116→                Log.d(TAG, "autoProcessPendingDocs: reset stuck doc id=${stuck.id}")
   117→            }
   118→
   119→            val pendingDocs = db.documentDao().getPendingWebviewDocs()
   120→            if (pendingDocs.isEmpty()) return@launch
   121→
   122→            Log.d(TAG, "autoProcessPendingDocs: found ${pendingDocs.size} pending docs")
   123→
   124→            // 依次处理每个待下载文档，每次只启动一个
   125→            for (doc in pendingDocs) {
   126→                // 检查是否已在处理中（parseStatus=5表示处理中）
   127→                if (doc.parseStatus == 5) {
   128→                    Log.d(TAG, "autoProcessPendingDocs: skip already processing ${doc.sourceUrl}")
   129→                    continue
   130→                }
   131→
   132→                // 标记为处理中（parseStatus=5）
   133→                db.documentDao().update(doc.copy(parseStatus = 5))
   134→
   135→                // 启动WebView处理
   136→                withContext(Dispatchers.Main) {
   137→                    val intent = Intent(getApplication(), WebViewActivity::class.java).apply {
   138→                        putExtra("url", doc.sourceUrl)
   139→                        putExtra("smsId", doc.smsId)
   140→                        putExtra("docId", doc.id)
   141→                        putExtra("autoMode", true) // 标记为自动模式
   142→                        addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
   143→                    }
   144→                    getApplication<Application>().startActivity(intent)
   145→                }
   146→
   147→                // 等待当前WebView处理完成后再处理下一个
   148→                // 每个WebView最多需要90秒（超时时间），这里设置100秒确保安全
   149→                delay(100000)
   150→            }
   151→        }
   152→    }
